  if (m + n !== c.length) return false;
  const dp = new Array(n + 1).fill(false);
  dp[0] = true;
  for (let j = 1; j <= n; j++) dp[j] = dp[j-1] && b[j-1] === c[j-1];
  for (let i = 1; i <= m; i++) {
    dp[0] = dp[0] && a[i-1] === c[i-1];
    for (let j = 1; j <= n; j++) {
      dp[j] = (dp[j] && a[i-1] === c[i+j-1]) || (dp[j-1] && b[j-1] === c[i+j-1]);
